import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"正阳门（箭楼）","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/zhengyangmen.md","filePath":"landmarks/zhengyangmen.md","lastUpdated":1784773307000}'),n={name:"landmarks/zhengyangmen.md"};function d(i,t,s,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="正阳门-箭楼" tabindex="-1">正阳门（箭楼） <a class="header-anchor" href="#正阳门-箭楼" aria-label="Permalink to &quot;正阳门（箭楼）&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-3bqa0rGhVSA?w=1200" alt="正阳门"></p><blockquote><p>&quot;国门第一楼，守望京城六百年。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>正阳门，俗称前门，位于北京市中轴线上，是明清北京内城的正门。正阳门由城楼和箭楼两部分组成，是北京城内唯一一座城楼和箭楼都完整保存下来的城门。正阳门是北京城的标志性建筑之一，也是中轴线上的重要节点。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线前门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区正阳门</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="明代始建" tabindex="-1">明代始建 <a class="header-anchor" href="#明代始建" aria-label="Permalink to &quot;明代始建&quot;">​</a></h3><p>正阳门始建于明永乐十八年（1420年），是明清北京内城的正门。正阳门的名称取自&quot;圣主当阳，日至中天&quot;，寓意皇帝的统治如日中天。</p><h3 id="清代重修" tabindex="-1">清代重修 <a class="header-anchor" href="#清代重修" aria-label="Permalink to &quot;清代重修&quot;">​</a></h3><p>清代对正阳门进行了多次重修，保持了明代建筑的原貌。正阳门一直是北京城的正门，皇帝出巡、重要仪式等都要经过正阳门。</p><h3 id="近代变迁" tabindex="-1">近代变迁 <a class="header-anchor" href="#近代变迁" aria-label="Permalink to &quot;近代变迁&quot;">​</a></h3><p>民国时期，正阳门城楼和箭楼都曾遭受破坏。1980年代以来，正阳门进行了大规模的修复，恢复了原有的建筑风貌。</p><h4 id="重要事件" tabindex="-1">重要事件 <a class="header-anchor" href="#重要事件" aria-label="Permalink to &quot;重要事件&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1420年</td><td style="text-align:left;">正阳门始建</td></tr><tr><td style="text-align:left;">1644年</td><td style="text-align:left;">李自成攻入北京，正阳门受损</td></tr><tr><td style="text-align:left;">1900年</td><td style="text-align:left;">八国联军入侵，正阳门被毁</td></tr><tr><td style="text-align:left;">1915年</td><td style="text-align:left;">正阳门城楼被拆除</td></tr><tr><td style="text-align:left;">1978年</td><td style="text-align:left;">正阳门箭楼修复</td></tr><tr><td style="text-align:left;">1988年</td><td style="text-align:left;">正阳门城楼复建</td></tr></tbody></table><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="城楼" tabindex="-1">城楼 <a class="header-anchor" href="#城楼" aria-label="Permalink to &quot;城楼&quot;">​</a></h3><p>正阳门城楼是北京城内最高大的城门楼，建筑宏伟壮观。</p><h4 id="建筑参数" tabindex="-1">建筑参数 <a class="header-anchor" href="#建筑参数" aria-label="Permalink to &quot;建筑参数&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">约42米</td></tr><tr><td style="text-align:left;"><strong>面阔</strong></td><td style="text-align:left;">七间</td></tr><tr><td style="text-align:left;"><strong>进深</strong></td><td style="text-align:left;">三间</td></tr><tr><td style="text-align:left;"><strong>屋顶形式</strong></td><td style="text-align:left;">重檐歇山顶</td></tr><tr><td style="text-align:left;"><strong>瓦色</strong></td><td style="text-align:left;">灰筒瓦绿剪边</td></tr></tbody></table><h4 id="建筑特色-1" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色-1" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h4><ul><li><strong>高度</strong>：正阳门城楼是北京城内最高大的城门楼</li><li><strong>结构</strong>：城楼为重檐歇山顶，气势恢宏</li><li><strong>功能</strong>：城楼用于瞭望和防御</li></ul><h3 id="箭楼" tabindex="-1">箭楼 <a class="header-anchor" href="#箭楼" aria-label="Permalink to &quot;箭楼&quot;">​</a></h3><p>正阳门箭楼位于城楼前方，是防御性建筑。</p><h4 id="建筑参数-1" tabindex="-1">建筑参数 <a class="header-anchor" href="#建筑参数-1" aria-label="Permalink to &quot;建筑参数&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">约38米</td></tr><tr><td style="text-align:left;"><strong>面阔</strong></td><td style="text-align:left;">七间</td></tr><tr><td style="text-align:left;"><strong>进深</strong></td><td style="text-align:left;">三间</td></tr><tr><td style="text-align:left;"><strong>屋顶形式</strong></td><td style="text-align:left;">重檐歇山顶</td></tr></tbody></table><h4 id="建筑特色-2" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色-2" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h4><ul><li><strong>防御功能</strong>：箭楼四面有箭窗，用于射击</li><li><strong>建筑形式</strong>：重檐歇山顶，与城楼相呼应</li><li><strong>文化内涵</strong>：箭楼是城门防御体系的重要组成部分</li></ul><h3 id="瓮城" tabindex="-1">瓮城 <a class="header-anchor" href="#瓮城" aria-label="Permalink to &quot;瓮城&quot;">​</a></h3><p>正阳门原有瓮城，是城门防御体系的重要组成部分。瓮城在民国时期被拆除，现仅存遗址。</p><h2 id="主要看点" tabindex="-1">主要看点 <a class="header-anchor" href="#主要看点" aria-label="Permalink to &quot;主要看点&quot;">​</a></h2><h3 id="城楼展览" tabindex="-1">城楼展览 <a class="header-anchor" href="#城楼展览" aria-label="Permalink to &quot;城楼展览&quot;">​</a></h3><p>正阳门城楼内有丰富的展览，展示了正阳门的历史和文化。</p><h4 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><ul><li><strong>历史沿革</strong>：正阳门的建筑历史</li><li><strong>中轴线文化</strong>：北京中轴线的历史和文化</li><li><strong>城门文化</strong>：中国古代城门建筑的特色</li></ul><h3 id="箭楼展览" tabindex="-1">箭楼展览 <a class="header-anchor" href="#箭楼展览" aria-label="Permalink to &quot;箭楼展览&quot;">​</a></h3><p>正阳门箭楼内有关于北京城门防御体系的展览。</p><h4 id="展览内容-1" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容-1" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><ul><li><strong>防御体系</strong>：北京城门的防御体系</li><li><strong>军事文化</strong>：中国古代军事文化</li><li><strong>建筑艺术</strong>：城门建筑的艺术特色</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约1小时）</strong>：</p><p>入口 → 箭楼 → 城楼 → 展览 → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>预约参观</strong>：正阳门实行预约制，建议提前在官网或微信公众号预约</li><li><strong>最佳时间</strong>：建议与前门大街、大栅栏一起游览</li><li><strong>拍照位置</strong>：正阳门广场、箭楼前都是绝佳拍照点</li><li><strong>讲解服务</strong>：可以租用讲解器，了解更多历史知识</li><li><strong>周边游览</strong>：参观完后可以到前门大街、大栅栏游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">2号线前门站B口或C口</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">1、2、52、82、120路前门站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;正阳门&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">前门大街</td><td style="text-align:center;">步行1分钟</td><td style="text-align:left;">老北京商业街</td></tr><tr><td style="text-align:left;">大栅栏</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老北京商业街</td></tr><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">世界最大城市广场</td></tr><tr><td style="text-align:left;">国家博物馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">国家级博物馆</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">明清皇宫</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>正阳门是北京城的象征，也是中轴线上的重要节点。&quot;正阳&quot;二字寓意着光明正大、蒸蒸日上，体现了中国古代的文化理念。</p><p>正阳门不仅是一座城门，更是北京历史文化的见证。从明清到近代，正阳门见证了北京城的沧桑巨变，也承载了北京人的记忆和情感。</p><hr><p><strong>📍 地址</strong>：北京市东城区正阳门 <strong>🚇 地铁</strong>：2号线前门站B口或C口 <strong>📞 电话</strong>：010-63031501</p><p><strong>💡 Tips</strong>：正阳门的夜景非常壮观，建议傍晚前往，欣赏灯光下的正阳门。</p>',56)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
